export const Schema = z.object({
    俱乐部: z.object({
        当前聚会: z.object({
            编号: z.string().prefault(''),
            状态: z.enum(['未开始', '进行中']).prefault('未开始'),
            开始楼层: z.coerce.number().prefault(0),
            主题: z.string().prefault(''),
        }).prefault({}),
        照片计数: z.coerce.number().prefault(0),
    }).prefault({}),
    // 每个角色各自拥有独立的数据，通过 MVU 快照实现楼层回滚
    磁带索引: z.record(z.string().describe('角色代号'), z.object({
        状态: z.enum(['活跃', '离场', '待命']).prefault('活跃'),
        真实度: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
        // ═══ 可回滚字段（从世界书导入，同步时写回） ═══
        标记: z.string().prefault(''), // "[初来乍到][打破禁忌]"
        身体痕迹: z.string().prefault(''),
        俱乐部人际: z.string().prefault(''),
        聚会履历草稿: z.string().prefault(''), // 当前聚会产生的未同步履历
        待同步照片: z.array(z.string()).prefault([]), // 照片 ID 列表
        同步版本: z.coerce.number().prefault(0),
    }).prefault({})).prefault({}),
});
